import{_ as t,o as e,c as n,a3 as r}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"扫描策略与关联管理","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/worldbook/scanning-strategy.md","filePath":"user-guide/tools/llm-chat/worldbook/scanning-strategy.md","lastUpdated":1778239080000}'),o={name:"user-guide/tools/llm-chat/worldbook/scanning-strategy.md"};function l(i,a,s,g,h,d){return e(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="扫描策略与关联管理" tabindex="-1">扫描策略与关联管理 <a class="header-anchor" href="#扫描策略与关联管理" aria-label="Permalink to &quot;扫描策略与关联管理&quot;">​</a></h1><p>世界书的效能很大程度上取决于扫描策略的配置，这决定了系统如何从海量对话中挖掘关键词。</p><h2 id="_1-扫描机制" tabindex="-1">1. 扫描机制 <a class="header-anchor" href="#_1-扫描机制" aria-label="Permalink to &quot;1. 扫描机制&quot;">​</a></h2><p>当用户发送消息或系统准备生成回复时，世界书处理器 (Worldbook Processor) 会执行以下操作：</p><ol><li><strong>提取文本</strong>: 获取最近的对话历史。</li><li><strong>关键词匹配</strong>: 在提取的文本中搜索所有关联世界书的关键词。</li><li><strong>递归扫描 (Recursive Scan)</strong>: 如果匹配到的条目内容中也包含关键词，系统会继续扫描这些内容，直到没有新条目被触发。</li><li><strong>角色过滤</strong>: 检查条目是否设置了角色过滤（例如：仅当当前 Agent 是“医生”时才触发医疗知识条目）。</li></ol><h2 id="_2-扫描深度-scanning-depth" tabindex="-1">2. 扫描深度 (Scanning Depth) <a class="header-anchor" href="#_2-扫描深度-scanning-depth" aria-label="Permalink to &quot;2. 扫描深度 (Scanning Depth)&quot;">​</a></h2><p>扫描深度决定了系统“往回看”多少条消息：</p><ul><li><strong>深度为 1</strong>: 仅扫描当前发送的这一条消息。</li><li><strong>深度为 5</strong>: 扫描最近的 5 条对话记录。</li><li><strong>平衡点</strong>: 深度越大，触发越精准，但计算开销和 Token 消耗也越高。建议设置为 3-5。</li></ul><h2 id="_3-关联管理" tabindex="-1">3. 关联管理 <a class="header-anchor" href="#_3-关联管理" aria-label="Permalink to &quot;3. 关联管理&quot;">​</a></h2><h3 id="全局世界书" tabindex="-1">全局世界书 <a class="header-anchor" href="#全局世界书" aria-label="Permalink to &quot;全局世界书&quot;">​</a></h3><p>在 <strong>聊天设置 -&gt; 世界书</strong> 中关联的书库。这些世界书对所有 Agent 和所有会话生效，适合存放通用的常识或系统规则。</p><h3 id="agent-专属世界书" tabindex="-1">Agent 专属世界书 <a class="header-anchor" href="#agent-专属世界书" aria-label="Permalink to &quot;Agent 专属世界书&quot;">​</a></h3><p>在 <a href="./../agents/parameters#2-关联资源">Agent 编辑器</a> 中关联。</p><ul><li><strong>优先级</strong>: Agent 专属世界书的条目通常具有更高的注入优先级。</li><li><strong>配置覆盖</strong>: Agent 可以独立设置是否启用“递归扫描”以及自定义“扫描深度”。</li></ul><h2 id="_4-调试与优化" tabindex="-1">4. 调试与优化 <a class="header-anchor" href="#_4-调试与优化" aria-label="Permalink to &quot;4. 调试与优化&quot;">​</a></h2><p>如果你发现世界书没有按预期触发，或者注入了太多无关内容，可以：</p><ol><li><strong>使用上下文分析器</strong>: 在<a href="./../context-pipeline/analyzer">分析器</a>的“结构化视图”中，你可以清晰看到哪些条目被匹配、匹配的原因以及它们最终所在的位置。</li><li><strong>检查全词匹配</strong>: 如果关键词是“人”，可能会错误触发“人生”、“人民”。开启“全词匹配”可以解决此问题。</li><li><strong>调整扫描深度</strong>: 如果设定是在几轮对话前提到的，尝试增加扫描深度。</li></ol><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./../agents/index">Agent 概览</a></li><li><a href="./../context-pipeline/analyzer">上下文分析器</a></li></ul>',20)])])}const p=t(o,[["render",l]]);export{u as __pageData,p as default};
